        `}_toggleGridLines(){this._showGridLines=!this._showGridLines,this._updatePreviewCard(),s.OC.debug("[DataGridStudioV4] Grid lines toggled:",this._showGridLines)}_toggleAnimations(){this._showAnimations=!this._showAnimations,this._updatePreviewCard(),s.OC.debug("[DataGridStudioV4] Animations toggled:",this._showAnimations)}_renderModeTab(){const e=this._workingConfig.data_mode||"decorative";return nn`
